        lock (_lock) { _queue.Enqueue(item); }
        _newEvent.Set();
    }

    public void Stop()
    {
        _thread.Interrupt(); // wake from WaitOne
        _thread.Join(5000);
        if (_thread.IsAlive)
            _thread.Abort();
    }
